import 'package:flutter/material.dart';import 'package:flutter_riverpod/flutter_riverpod.dart';import '../../core/database/app_database.dart';import '../../core/utils/app_utils.dart';import '../data/app_repository.dart';class DebtsScreen extends ConsumerWidget{const DebtsScreen({super.key});Future<void> pay(BuildContext context,WidgetRef ref,Debt d)async{final c=TextEditingController();final a=await showDialog<double>(context:context,builder:(x)=>AlertDialog(title:const Text('Record payment'),content:TextField(controller:c,keyboardType:TextInputType.number,decoration:InputDecoration(labelText:'Amount (balance ${formatGhs(d.balance)})')),actions:[TextButton(onPressed:()=>Navigator.pop(x),child:const Text('Cancel')),FilledButton(onPressed:()=>Navigator.pop(x,double.tryParse(c.text)),child:const Text('Save'))]));if(a!=null)await ref.read(repoProvider).payDebt(d,a,'cash');}@override Widget build(BuildContext context,WidgetRef ref){final a=ref.watch(debtsProvider),customers=ref.watch(customersProvider).valueOrNull??[];return Scaffold(appBar:AppBar(title:const Text('Customer debts')),body:a.when(loading:()=>const Center(child:CircularProgressIndicator()),error:(e,_)=>Center(child:Text('$e')),data:(v){final open=v.where((x)=>x.balance>0).toList();return open.isEmpty?const Center(child:Text('No outstanding debts')):ListView.builder(padding:const EdgeInsets.all(16),itemCount:open.length,itemBuilder:(_,i){final d=open[i];String name='Customer';for(final c in customers){if(c.id==d.customerId){name=c.name;break;}}return Card(child:ListTile(title:Text(name,style:const TextStyle(fontWeight:FontWeight.w900)),subtitle:Text('Original ${formatGhs(d.originalAmount)}'),trailing:TextButton(onPressed:()=>pay(context,ref,d),child:Text(formatGhs(d.balance)))));});}));}}
